import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id);
}

function getDirectionalNeighbor(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

function bridgeLinesForKey(key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const px1 = x1 * GRID;
  const py1 = y1 * GRID;
  const px2 = x2 * GRID;
  const py2 = y2 * GRID;

  const vertical = px1 === px2;
  const offset = 4;

  if (count === 1) {
    return [
      {
        x1: px1,
        y1: py1,
        x2: px2,
        y2: py2,
      },
    ];
  }

  if (vertical) {
    return [
      { x1: px1 - offset, y1: py1, x2: px2 - offset, y2: py2 },
      { x1: px1 + offset, y1: py1, x2: px2 + offset, y2: py2 },
    ];
  }

  return [
    { x1: px1, y1: py1 - offset, x2: px2, y2: py2 - offset },
    { x1: px1, y1: py1 + offset, x2: px2, y2: py2 + offset },
  ];
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(() => islands[0]?.id ?? null);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  // Reset when puzzle changes
  useEffect(() => {
    setBridges(new Map());
    setSelectedIslandId(null);
    setError(null);
    setCursorIslandId(puzzles[puzzleIndex].islands[0]?.id ?? null);
  }, [puzzleIndex]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const solved = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValid(valid) {
    if (valid) setError(null);
  }

  function applyToggle(from, to) {
    const key = canonicalBridgeKey(from, to);
    const existing = bridges.get(key) ?? 0;
    const next = existing === 0 ? 1 : existing === 1 ? 2 : 0;

    if (next === 0) {
      const nb = new Map(bridges);
      nb.delete(key);
      setBridges(nb);
      setError(null);
      return;
    }

    const delta = next - existing;
    const check = canAddBridge(islands, bridges, from, to, delta);
    if (!check.valid) {
      setError(check.error);
      return;
    }

    const nb = new Map(bridges);
    nb.set(key, next);
    setBridges(nb);
    clearErrorOnValid(true);
  }

  function onIslandClick(isl, e) {
    e.preventDefault();
    setCursorIslandId(isl.id);

    if (selectedIslandId == null) {
      setSelectedIslandId(isl.id);
      return;
    }

    if (selectedIslandId === isl.id) {
      // Clicking same island keeps selection.
      return;
    }

    const from = findIslandById(islands, selectedIslandId);
    const to = isl;
    applyToggle(from, to);
    setSelectedIslandId(null);
  }

  function onBridgeClick(key, e) {
    // Right click or Ctrl+click removes entirely
    if (e.type === 'contextmenu' || e.ctrlKey) {
      e.preventDefault();
      const nb = new Map(bridges);
      nb.delete(key);
      setBridges(nb);
      setSelectedIslandId(null);
      setError(null);
    }
  }

  function reset() {
    setBridges(new Map());
    setSelectedIslandId(null);
    setError(null);
  }

  useEffect(() => {
    const el = svgRef.current;
    if (el) el.focus();
  }, []);

  function onKeyDown(e) {
    if (!cursorIslandId && islands.length) setCursorIslandId(islands[0].id);
    const cur = findIslandById(islands, cursorIslandId);
    if (!cur) return;

    if (e.key === 'Escape') {
      setSelectedIslandId(null);
      setError(null);
      return;
    }

    const dirByKey = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down',
    };

    if (dirByKey[e.key]) {
      e.preventDefault();
      const nb = getDirectionalNeighbor(islands, cur, dirByKey[e.key]);
      if (nb) setCursorIslandId(nb.id);
      return;
    }

    if (e.key === 'Enter') {
      e.preventDefault();
      if (selectedIslandId == null) {
        setSelectedIslandId(cur.id);
        return;
      }
      if (selectedIslandId === cur.id) return;

      const from = findIslandById(islands, selectedIslandId);
      const to = cur;
      applyToggle(from, to);
      setSelectedIslandId(null);
    }
  }

  const bridgeEntries = Array.from(bridges.entries()).filter(([, n]) => n > 0);

  return (
    <div style={{ position: 'absolute', left: 0, top: 0 }}>
      <div
        style={{
          padding: '8px',
          display: 'flex',
          gap: '12px',
          alignItems: 'center',
        }}
      >
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          >
            {puzzles.map((p, idx) => (
              <option key={p.id} value={idx}>
                {p.name}
              </option>
            ))}
          </select>
        </label>
        <button onClick={reset}>Reset</button>
        {error ? <div className="error-message">{error}</div> : null}
        {solved ? <div className="victory-banner">SOLVED!</div> : null}
      </div>

      <svg
        ref={svgRef}
        tabIndex={0}
        width={SVG_W}
        height={SVG_H}
        style={{ display: 'block', outline: 'none' }}
        onKeyDown={onKeyDown}
      >
        {/* Bridges */}
        {bridgeEntries.flatMap(([key, n]) => {
          const lines = bridgeLinesForKey(key, n);
          return lines.map((ln, idx) => (
            <line
              key={`${key}-${idx}`}
              x1={ln.x1}
              y1={ln.y1}
              x2={ln.x2}
              y2={ln.y2}
              stroke="#0f0"
              strokeWidth={3}
              onClick={(e) => onBridgeClick(key, e)}
              onContextMenu={(e) => onBridgeClick(key, e)}
            />
          ));
        })}

        {/* Cursor (must not be a circle) */}
        {cursorIslandId != null ? (() => {
          const isl = findIslandById(islands, cursorIslandId);
          if (!isl) return null;
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const size = 34;
          const isSelected = selectedIslandId === isl.id;
          return (
            <rect
              x={px - size / 2}
              y={py - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke={isSelected ? '#fff' : '#0f0'}
              strokeWidth={2}
              strokeDasharray={isSelected ? '0' : '4 3'}
            />
          );
        })() : null}

        {/* Islands */}
        {islands.map((isl) => {
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const current = counts.get(isl.id) ?? 0;
          const over = current > isl.value;
          return (
            <g key={isl.id} onClick={(e) => onIslandClick(isl, e)} style={{ cursor: 'pointer' }}>
              <circle
                cx={px}
                cy={py}
                r={16}
                fill="black"
                stroke={over ? 'red' : '#0f0'}
                strokeWidth={2}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={16}
                fill="#0f0"
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
